solution_code:
#include <iostream>
#include <iomanip>
#include <string>

struct Person
{
    std::string name;
    int age;
    double height;
};

int main()
{
    std::string name;
    int age{};
    double height{};
    std::cin >> name >> age >> height;

    Person p1 { name, age, height };
    Person p2 { .name = name, .height = height };
    Person p3 {};

    std::cout << std::fixed << std::setprecision(1);

    std::cout << p1.name << ' ' << p1.age << ' ' << p1.height << '\n';
    std::cout << p2.name << ' ' << p2.age << ' ' << p2.height << '\n';
    std::cout << p3.name << ' ' << p3.age << ' ' << p3.height << '\n';

    return 0;
}

